import{_ as e,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"调试","description":"","frontmatter":{"read_when":["你需要检查原始模型输出以查找推理泄漏","你想在迭代时以监视模式运行 Gateway 网关","你需要可重复的调试工作流"],"summary":"调试工具：监视模式、原始模型流和追踪推理泄漏","title":"调试","x-i18n":{"generated_at":"2026-02-03T07:47:23Z","model":"claude-opus-4-5","provider":"pi","source_hash":"504c824bff4790006c8b73600daca66b919e049178e9711e6e65b6254731911a","source_path":"help/debugging.md","workflow":15}},"headers":[],"relativePath":"zh-CN/help/debugging.md","filePath":"zh-CN/help/debugging.md","lastUpdated":1771906665000}'),p={name:"zh-CN/help/debugging.md"};function l(t,s,d,h,o,r){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="调试" tabindex="-1"><a class="header-anchor" href="#调试">#</a> 调试</h1><p>本页介绍用于流式输出的调试辅助工具，特别是当提供商将推理混入正常文本时。</p><h2 id="运行时调试覆盖" tabindex="-1"><a class="header-anchor" href="#运行时调试覆盖">#</a> 运行时调试覆盖</h2><p>在聊天中使用 <code>/debug</code> 设置<strong>仅运行时</strong>配置覆盖（内存中，不写入磁盘）。 <code>/debug</code> 默认禁用；通过 <code>commands.debug: true</code> 启用。 当你需要切换不常用的设置而不编辑 <code>opensoul.json</code> 时，这非常方便。</p><p>示例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/debug show</span></span>
<span class="line"><span>/debug set messages.responsePrefix=&quot;[opensoul]&quot;</span></span>
<span class="line"><span>/debug unset messages.responsePrefix</span></span>
<span class="line"><span>/debug reset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>/debug reset</code> 清除所有覆盖并返回到磁盘上的配置。</p><h2 id="gateway-网关监视模式" tabindex="-1"><a class="header-anchor" href="#gateway-网关监视模式">#</a> Gateway 网关监视模式</h2><p>为了快速迭代，在文件监视器下运行 Gateway 网关：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这映射到：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tsx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/entry.ts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在 <code>gateway:watch</code> 后添加任何 Gateway 网关 CLI 标志，它们将在每次重启时传递。</p><h2 id="dev-配置文件-dev-gateway-网关-dev" tabindex="-1"><a class="header-anchor" href="#dev-配置文件-dev-gateway-网关-dev">#</a> Dev 配置文件 + dev Gateway 网关（--dev）</h2><p>使用 dev 配置文件来隔离状态，并启动一个安全、可丢弃的调试设置。有<strong>两个</strong> <code>--dev</code> 标志：</p><ul><li><strong>全局 <code>--dev</code>（配置文件）：</strong> 将状态隔离到 <code>~/.opensoul-dev</code> 下，并将 Gateway 网关端口默认为 <code>19001</code>（派生端口随之移动）。</li><li><strong><code>gateway --dev</code>：告诉 Gateway 网关在缺失时自动创建默认配置 + 工作区</strong>（并跳过 BOOTSTRAP.md）。</li></ul><p>推荐流程（dev 配置文件 + dev 引导）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:dev</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果你还没有全局安装，请通过 <code>pnpm opensoul ...</code> 运行 CLI。</p><p>这会执行：</p><ol><li><p><strong>配置文件隔离</strong>（全局 <code>--dev</code>）</p><ul><li><code>OPENSOUL_PROFILE=dev</code></li><li><code>OPENSOUL_STATE_DIR=~/.opensoul-dev</code></li><li><code>OPENSOUL_CONFIG_PATH=~/.opensoul-dev/opensoul.json</code></li><li><code>OPENSOUL_GATEWAY_PORT=19001</code>（浏览器/画布相应移动）</li></ul></li><li><p><strong>Dev 引导</strong>（<code>gateway --dev</code>）</p><ul><li>如果缺失则写入最小配置（<code>gateway.mode=local</code>，绑定 loopback）。</li><li>将 <code>agent.workspace</code> 设置为 dev 工作区。</li><li>设置 <code>agent.skipBootstrap=true</code>（无 BOOTSTRAP.md）。</li><li>如果缺失则填充工作区文件： <code>AGENTS.md</code>、<code>SOUL.md</code>、<code>TOOLS.md</code>、<code>IDENTITY.md</code>、<code>USER.md</code>、<code>HEARTBEAT.md</code>。</li><li>默认身份：<strong>C3‑PO</strong>（礼仪机器人）。</li><li>在 dev 模式下跳过渠道提供商（<code>OPENSOUL_SKIP_CHANNELS=1</code>）。</li></ul></li></ol><p>重置流程（全新开始）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:dev:reset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意：<code>--dev</code> 是<strong>全局</strong>配置文件标志，会被某些运行器吞掉。 如果你需要明确拼写，请使用环境变量形式：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>--reset</code> 清除配置、凭证、会话和 dev 工作区（使用 <code>trash</code>，而非 <code>rm</code>），然后重新创建默认的 dev 设置。</p><p>提示：如果非 dev Gateway 网关已在运行（launchd/systemd），请先停止它：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="原始流日志-opensoul" tabindex="-1"><a class="header-anchor" href="#原始流日志-opensoul">#</a> 原始流日志（OpenSoul）</h2><p>OpenSoul 可以在任何过滤/格式化之前记录<strong>原始助手流</strong>。 这是查看推理是否作为纯文本增量到达（或作为单独的思考块）的最佳方式。</p><p>通过 CLI 启用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可选路径覆盖：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/logs/raw-stream.jsonl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>等效环境变量：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_RAW_STREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_RAW_STREAM_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.opensoul/logs/raw-stream.jsonl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>默认文件：</p><p><code>~/.opensoul/logs/raw-stream.jsonl</code></p><h2 id="原始块日志-pi-mono" tabindex="-1"><a class="header-anchor" href="#原始块日志-pi-mono">#</a> 原始块日志（pi-mono）</h2><p>要在解析为块之前捕获<strong>原始 OpenAI 兼容块</strong>，pi-mono 暴露了一个单独的日志记录器：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PI_RAW_STREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可选路径：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PI_RAW_STREAM_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.pi-mono/logs/raw-openai-completions.jsonl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>默认文件：</p><p><code>~/.pi-mono/logs/raw-openai-completions.jsonl</code></p><blockquote><p>注意：这仅由使用 pi-mono 的 <code>openai-completions</code> 提供商的进程发出。</p></blockquote><h2 id="安全注意事项" tabindex="-1"><a class="header-anchor" href="#安全注意事项">#</a> 安全注意事项</h2><ul><li>原始流日志可能包含完整提示、工具输出和用户数据。</li><li>保持日志在本地并在调试后删除它们。</li><li>如果你分享日志，请先清除密钥和个人身份信息。</li></ul>`,48)])])}const k=e(p,[["render",l]]);export{g as __pageData,k as default};
